package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// Public event-type strings emitted by agentlib.FizeauService.Execute, mirrored
// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
// drain loop does not have to import the agent's internal/harnesses
// package (which is module-private).
const (
	serviceEventRoutingDecision = "routing_decision"
	serviceEventFinal           = "final"
)

// ServiceEvent payload types are now aliases to the upstream v0.8.0 public
// types (agent-f0bc5467). DDx previously maintained byte-for-byte shadow
// copies of these structs because CONTRACT-003 hadn't published them; that
// left the consumer carrying stream-adjacent knowledge and drifted whenever
// upstream shapes changed. With v0.8.0 the types are public and stable.
//
// Aliases rather than an outright delete so existing call sites keep
// working without a sweep. New code can (and should) use agentlib types
// directly.
type (
	serviceFinalData = agentlib.ServiceFinalData
)

type serviceRoutingActual struct {
	Harness                     string
	Provider                    string
	Model                       string
	PredictedPower              int
	PredictedSpeedTPS           float64
	PredictedCostUSDPer1kTokens float64
	PredictedCostSource         string
}

// useNewAgentPath reports whether RunAgent should dispatch to the new
// agentlib.FizeauService.Execute path. Default is on. Set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
// hatch.
func useNewAgentPath() bool {
	switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
	case "0", "false", "FALSE", "False":
		return false
	default:
		return true
	}
}

// runAgentViaService is the new RunAgent dispatch path that drives the
// agent through agentlib.FizeauService.Execute and drains the resulting event
// channel into a DDx Result. Old in-package code paths (RunAgent legacy
// loop, embeddedCompactionConfig, buildAgentProvider, findTool, and
// wrapProviderWithDeadlines) stay in place; this function does NOT call them.
//
// Stall detection: we delegate to the agent's StallPolicy. The agent
// emits a stall event then a final event with Status="stalled".
func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
	promptText, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, "agent")
	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	wd := opts.WorkDir
	if wd == "" {
		wd, _ = os.Getwd()
	}

	// Construct the service. Reuses NewServiceFromWorkDir so provider/model
	// routing data lands on the agent the same way every other DDx command
	// constructs it (see serviceconfig.go).
	svc, err := NewServiceFromWorkDir(wd)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}

	// Resolve where to write the per-request session log.
	logDir := opts.SessionLogDir
	if logDir == "" {
		logDir = r.Config.SessionLogDir
	}
	if logDir == "" {
		logDir = DefaultLogDir
	}

	providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)

	// Build the public ExecuteRequest per CONTRACT-003.
	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Provider:        opts.Provider,
		Harness:         "agent",
		ModelRef:        opts.ModelRef,
		Reasoning:       agentlib.Reasoning(opts.Effort),
		Permissions:     opts.Permissions,
		WorkDir:         wd,
		Timeout:         wallClock,
		IdleTimeout:     timeout,
		ProviderTimeout: providerTimeout,
		SessionLogDir:   logDir,
		Metadata:        opts.Correlation,
		Role:            opts.Role,
		CorrelationID:   opts.CorrelationID,
	}

	parentCtx := opts.Context
	if parentCtx == nil {
		parentCtx = context.Background()
	}
	ctx, cancel := context.WithCancel(parentCtx)
	defer cancel()

	start := time.Now()
	events, err := svc.Execute(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	final, routing, actualPower, _ := drainServiceEvents(events)
	elapsed := time.Since(start)

	result := &Result{
		Harness:    "agent",
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		result.PredictedPower = routing.PredictedPower
		result.PredictedSpeedTPS = routing.PredictedSpeedTPS
		result.PredictedCostUSDPer1kTokens = routing.PredictedCostUSDPer1kTokens
		result.PredictedCostSource = routing.PredictedCostSource
	}
	if actualPower > 0 {
		result.ActualPower = actualPower
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int so the API can distinguish
			// "harness reported zero" from "harness didn't report". Treat
			// nil as zero for DDx's int-valued result struct.
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		result.ExitCode = final.ExitCode
		result.Error = final.Error
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
		}
		if final.SessionLogPath != "" {
			// surface as session ID for downstream cross-reference (mirrors
			// the legacy path's AgentSessionID population).
			result.AgentSessionID = final.SessionLogPath
		}
	}
	result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)

	promptSource := opts.PromptSource
	if promptSource == "" {
		if opts.PromptFile != "" {
			promptSource = opts.PromptFile
		} else {
			promptSource = "inline"
		}
	}
	r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
	r.recordRoutingOutcome(result, elapsed, opts)
	return result, nil
}

// drainServiceEvents reads service events and returns the final-event payload,
// the routing decision (when present in the routing_decision start event), the
// power of the selected model (0 when the routing_decision event does not
// include candidate power components), and any canonical progress payloads
// emitted by the service.
func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, *serviceRoutingActual, int, []agentlib.ServiceProgressData) {
	var final *serviceFinalData
	var routing *serviceRoutingActual
	var routingPower int
	var progress []agentlib.ServiceProgressData

	for ev := range events {
		switch string(ev.Type) {
		case serviceEventRoutingDecision:
			var payload struct {
				Harness    string `json:"harness"`
				Provider   string `json:"provider"`
				Model      string `json:"model"`
				Candidates []struct {
					Model              string  `json:"model"`
					Eligible           bool    `json:"eligible"`
					CostUSDPer1kTokens float64 `json:"cost_usd_per_1k_tokens"`
					CostSource         string  `json:"cost_source"`
					Components         struct {
						Power    int     `json:"power"`
						SpeedTPS float64 `json:"speed_tps"`
					} `json:"components"`
				} `json:"candidates"`
			}
			if err := json.Unmarshal(ev.Data, &payload); err == nil {
				routing = &serviceRoutingActual{
					Harness:  payload.Harness,
					Provider: payload.Provider,
					Model:    payload.Model,
				}
				for _, c := range payload.Candidates {
					if c.Eligible && c.Model == payload.Model {
						routingPower = c.Components.Power
						routing.PredictedPower = c.Components.Power
						routing.PredictedSpeedTPS = c.Components.SpeedTPS
						routing.PredictedCostUSDPer1kTokens = c.CostUSDPer1kTokens
						routing.PredictedCostSource = c.CostSource
						break
					}
				}
			}
		case agentlib.ServiceEventTypeProgress:
			var data agentlib.ServiceProgressData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				progress = append(progress, data)
			}
		case serviceEventFinal:
			var data serviceFinalData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				final = &data
			}
		}
	}
	return final, routing, routingPower, progress
}

	exitCode = agentResult.ExitCode
	tokens = agentResult.Tokens
	inputTokens = agentResult.InputTokens
	outputTokens = agentResult.OutputTokens
	costUSD = agentResult.CostUSD
	if agentResult.Error != "" {
		agentErrMsg = agentResult.Error
	}
	if agentResult.Stderr != "" {
		agentStderr = agentResult.Stderr
	}
	if agentResult.Model != "" {
		resultModel = agentResult.Model
	}
	if agentResult.Provider != "" {
		resultProvider = agentResult.Provider
	}
	if agentResult.Harness != "" {
		resultHarness = agentResult.Harness
	}
	if agentResult.ActualPower > 0 {
		actualPower = agentResult.ActualPower
	}
	predictedPower = agentResult.PredictedPower
	predictedSpeedTPS = agentResult.PredictedSpeedTPS
	predictedCostUSDPer1kTokens = agentResult.PredictedCostUSDPer1kTokens
	predictedCostSource = agentResult.PredictedCostSource
}
if agentErr != nil {
	if exitCode == 0 {
		exitCode = 1
	}
	agentErrMsg = agentErr.Error()
}

// Capture routing evidence from the agent result. These fields are
// populated by RunAgent (embedded harness) and RunScript (script harness).
routeReason := ""
routeBaseURL := ""
if agentResult != nil {
	routeReason = agentResult.RouteReason
	routeBaseURL = agentResult.ResolvedBaseURL
}

// Get the HEAD of the worktree after the agent ran.
resultRev, revErr := gitOps.HeadRev(wtPath)
if revErr != nil {
	res := &ExecuteBeadResult{
		BeadID:                      beadID,
		AttemptID:                   attemptID,
		WorkerID:                    runtime.WorkerID,
		BaseRev:                     baseRev,
		ResultRev:                   baseRev, // no commits readable; treat as no output
		Harness:                     resultHarness,
		Provider:                    resultProvider,
		Model:                       resultModel,
		ActualPower:                 actualPower,
		PredictedPower:              predictedPower,
		PredictedSpeedTPS:           predictedSpeedTPS,
		PredictedCostUSDPer1kTokens: predictedCostUSDPer1kTokens,
		PredictedCostSource:         predictedCostSource,
		SessionID:                   sessionID,
		DurationMS:                  int(finishedAt.Sub(startedAt).Milliseconds()),
		Tokens:                      tokens,
		CostUSD:                     costUSD,
		ExitCode:                    1,
		Error:                       agentErrMsg,
		Stderr:                      agentStderr,
		RateLimitBudget:             runtime.RateLimitMaxWait,
		Reason:                      revErr.Error(), // HeadRev failure; orchestrator prefers this over Error for Reason
		ExecutionDir:                artifacts.DirRel,
		PromptFile:                  artifacts.PromptRel,
		ManifestFile:                artifacts.ManifestRel,
		ResultFile:                  artifacts.ResultRel,
		StartedAt:                   startedAt,
		FinishedAt:                  finishedAt,
		Outcome:                     ExecuteBeadOutcomeTaskFailed,
	}
	res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)
	populateWorkerStatus(res)
	_ = writeArtifactJSON(artifacts.ResultAbs, res)
	return res, fmt.Errorf("failed to read worktree HEAD: %w", revErr)
}

// Write usage.json when the harness reports token usage or cost.
// Done before SynthesizeCommit so usage data is available in the
// preliminary result written for commit-message sourcing.
var usageFileRel string
if tokens > 0 || costUSD > 0 {
	usage := executeBeadUsage{
		AttemptID:    attemptID,

	costCap := escalation.NewCostCapTracker(maxCostUSD, func(harnessName string) bool {
		// Resolve the harness's billing class via the service. Treat any
		// resolution error as "count by default" (safe — we'd rather cap
		// early than silently overshoot).
		svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
		if svcErr != nil {
			return true
		}
		infos, err := svc.ListHarnesses(context.Background())
		if err != nil {
			return true
		}
		for _, h := range infos {
			if h.Name == harnessName {
				return escalation.CountsTowardCostCap(h.IsLocal, h.IsSubscription, h.CostClass)
			}
		}
		return true
	})
	accumulateBilledCost := func(report agent.ExecuteBeadReport) {
		costCap.Add(report.Harness, report.CostUSD)
	}
	costCapTripped := func() (agent.ExecuteBeadReport, bool) {
		if _, tripped := costCap.Tripped(); !tripped {
			return agent.ExecuteBeadReport{}, false
		}
		spent := costCap.Spent()
		return agent.ExecuteBeadReport{
			Status: agent.ExecuteBeadStatusExecutionFailed,
			Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, maxCostUSD),
		}, true
	}

	// singleTierAttempt runs one execution attempt with an explicit harness
	// and model. The caller controls MinPower per rung; this helper keeps the
	// profile stable and only advances the power floor.
	singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
		gitOps := &agent.RealGitOps{}
		attemptProvider := provider
		if resolvedProvider != "" {
			attemptProvider = resolvedProvider
		}
		loopOverrides := config.CLIOverrides{
			Harness:           resolvedHarness,
			Model:             resolvedModel,
			Provider:          attemptProvider,
			ModelRef:          modelRef,
			Profile:           profile,
			Effort:            effort,
			MinPower:          requestedMinPower,
			MaxPower:          maxPower,
			OpaquePassthrough: treatPassthroughAsOpaque,
		}
		if requestTimeout > 0 {
			loopOverrides.ProviderRequestTimeout = &requestTimeout
		}
		attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
		res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
			FromRev:     fromRev,
			BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
			AgentRunner: f.AgentRunnerOverride,
		}, gitOps)
		if execErr != nil && res == nil {
			return agent.ExecuteBeadReport{}, execErr
		}
		if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
			targetBead, _ := store.Get(beadID)
			landRes, _, landErr := agent.SubmitWithPreMergeChecks(
				ctx, projectRoot, targetBead, res,
				func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
				resolveClaimAssignee(), "ddx agent execute-loop",
				nil,
			)
			if landErr == nil {
				agent.ApplyLandResultToExecuteBeadResult(res, landRes)
			} else if execErr == nil {
				execErr = landErr
			}
		} else if res != nil && res.ResultRev == res.BaseRev {
			res.Outcome = "no-changes"
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		} else if res != nil && res.ExitCode != 0 {
			res.Outcome = "preserved"
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		}
		if execErr != nil {
			return agent.ExecuteBeadReport{}, execErr
		}
		return agent.ExecuteBeadReport{
			BeadID:                      res.BeadID,
			AttemptID:                   res.AttemptID,
			WorkerID:                    res.WorkerID,
			Harness:                     res.Harness,
			Provider:                    res.Provider,
			Model:                       res.Model,
			ActualPower:                 res.ActualPower,
			PredictedPower:              res.PredictedPower,
			PredictedSpeedTPS:           res.PredictedSpeedTPS,
			PredictedCostUSDPer1kTokens: res.PredictedCostUSDPer1kTokens,
			PredictedCostSource:         res.PredictedCostSource,
			Status:                      res.Status,
			Detail:                      res.Detail,
			SessionID:                   res.SessionID,
			BaseRev:                     res.BaseRev,
			ResultRev:                   res.ResultRev,
			PreserveRef:                 res.PreserveRef,
			NoChangesRationale:          res.NoChangesRationale,
			CostUSD:                     res.CostUSD,
			DurationMS:                  int64(res.DurationMS),
		}, nil
	}

	var ladderOnce sync.Once
	var ladder escalationFloorFinder
	loadLadder := func() escalationFloorFinder {
		ladderOnce.Do(func() {
			ladder = tierescalation.NewLadder(nil)
			svc, svcErr := agent.NewServiceFromWorkDir(projectRoot)
			if svcErr != nil {
				return
			}
			modelFilter := agentlib.ModelFilter{}
			if harness != "" {
				modelFilter.Harness = harness
			}
			modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
			defer cancel()
			models, listErr := svc.ListModels(modelCtx, modelFilter)
			if listErr != nil {
				return
			}
			ladder = tierescalation.NewLadder(models)
		})
		return ladder
	}

	worker := &agent.ExecuteBeadWorker{
		Store:    store,
		Reviewer: reviewer,
		Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
			// Stop AT THE START of each new bead claim if the cost cap has
			// already tripped — otherwise we'd burn one extra attempt before
			// halting the queue.
			if cappedReport, capped := costCapTripped(); capped {
				cappedReport.BeadID = beadID
				return cappedReport, nil
			}
			report, err := runEscalatingSingleTierAttempts(
				ctx,
				rcfg.MinPower(),
				loadLadder(),
				func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
					return singleTierAttempt(ctx, beadID, requestedMinPower, harness, provider, model)
				},
				nil,
			)
			if err == nil {
				accumulateBilledCost(report)
				if cappedReport, capped := costCapTripped(); capped {
					cappedReport.BeadID = beadID
					return cappedReport, nil
				}
			}
			return report, err
		}),
	}

	cliLandingOps := agent.RealLandingGitOps{}
	result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
		Once:          once,
		PollInterval:  pollInterval,
		Log:           cmd.OutOrStdout(),
		EventSink:     loopSink,
		WorkerID:      resolveClaimAssignee(),
		ProjectRoot:   projectRoot,
		SessionID:     loopSessionID,
		PreClaimHook:  buildCLIPreClaimHook(projectRoot, cliLandingOps),
		NoReview:      noReview,
		TargetBeadID:  tryTargetBeadID,
		ReviewCostCap: costCap,
	})
	tailCancel() // stop session log tailer
	if err != nil {
		return err
	}
	return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, asJSON)
}

func formatAttemptRouteEconomics(attempt agent.ExecuteBeadReport) string {
	if attempt.Harness == "" && attempt.Provider == "" && attempt.Model == "" {
		return ""
	}
	parts := []string{}
	if attempt.Harness != "" {
		parts = append(parts, "harness="+attempt.Harness)
	}
	if attempt.Provider != "" {
		parts = append(parts, "provider="+attempt.Provider)
	}
	if attempt.Model != "" {
		parts = append(parts, "model="+attempt.Model)
	}
	power := attempt.PredictedPower
	if power == 0 {
		power = attempt.ActualPower
	}
	if power > 0 {
		parts = append(parts, fmt.Sprintf("power=%d", power))
	}
	if attempt.PredictedSpeedTPS > 0 {
		parts = append(parts, fmt.Sprintf("speed=%.1f tok/s", attempt.PredictedSpeedTPS))
	}
	if attempt.PredictedCostUSDPer1kTokens > 0 {
		cost := fmt.Sprintf("cost=$%.6f/1k tok", attempt.PredictedCostUSDPer1kTokens)
		if attempt.PredictedCostSource != "" {
			cost += " source=" + attempt.PredictedCostSource
		}
		parts = append(parts, cost)
	} else if attempt.PredictedCostSource != "" {
		parts = append(parts, "cost_source="+attempt.PredictedCostSource)
	}
	return strings.Join(parts, " ")
}

func writeExecuteLoopResult(w io.Writer, projectRoot string, result *agent.ExecuteBeadLoopResult, asJSON bool) error {
	if asJSON {
		payload := struct {
			ProjectRoot string `json:"project_root"`
			*agent.ExecuteBeadLoopResult
		}{
			ProjectRoot:           projectRoot,
			ExecuteBeadLoopResult: result,
		}
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")

package agent

import (
	"encoding/json"
	"testing"
	"time"

	agentlib "github.com/DocumentDrivenDX/fizeau"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestDrainServiceEvents_CapturesRouteEconomics covers the routing_decision
// event's winning candidate (eligible=true, model matches payload.model)
// carrying power, speed, and cost telemetry. DDx must surface those fields
// from the selected eligible candidate without touching the final event.
func TestDrainServiceEvents_CapturesRouteEconomics(t *testing.T) {
	events := make(chan agentlib.ServiceEvent, 4)

	routingPayload, err := json.Marshal(map[string]any{
		"harness":  "agent",
		"provider": "anthropic",
		"model":    "claude-3-5-sonnet",
		"candidates": []map[string]any{
			{
				"model":      "claude-3-haiku",
				"eligible":   false,
				"components": map[string]any{"power": 20},
			},
			{
				"model":                  "claude-3-5-sonnet",
				"eligible":               true,
				"cost_usd_per_1k_tokens": 0.0125,
				"cost_source":            "catalog",
				"components": map[string]any{
					"power":     65,
					"speed_tps": 42.5,
				},
			},
		},
	})
	require.NoError(t, err)
	events <- agentlib.ServiceEvent{
		Type: "routing_decision",
		Time: time.Date(2026, 4, 30, 12, 0, 0, 0, time.UTC),
		Data: routingPayload,
	}

	finalPayload, err := json.Marshal(map[string]any{
		"status":     "success",
		"exit_code":  0,
		"final_text": "done",
	})
	require.NoError(t, err)
	events <- agentlib.ServiceEvent{
		Type: "final",
		Time: time.Date(2026, 4, 30, 12, 0, 1, 0, time.UTC),
		Data: finalPayload,
	}
	close(events)

	_, routing, actualPower, _ := drainServiceEvents(events)
	assert.Equal(t, 65, actualPower,
		"power must come from the eligible winning candidate in routing_decision.candidates")
	require.NotNil(t, routing)
	assert.Equal(t, 65, routing.PredictedPower)
	assert.Equal(t, 42.5, routing.PredictedSpeedTPS)
	assert.Equal(t, 0.0125, routing.PredictedCostUSDPer1kTokens)
	assert.Equal(t, "catalog", routing.PredictedCostSource)
}

// TestDrainServiceEvents_ForwardsCanonicalProgressPayload proves canonical
// Fizeau progress is surfaced directly from the ServiceEvent stream rather
// than being reconstructed from session-log JSONL.
func TestDrainServiceEvents_ForwardsCanonicalProgressPayload(t *testing.T) {
	events := make(chan agentlib.ServiceEvent, 2)
	progressPayload, err := json.Marshal(map[string]any{
		"phase":           "tool",
		"state":           "complete",
		"task_id":         "ddx-1234",
		"turn_index":      7,
		"tool_name":       "apply_patch",
		"action":          "add test implementation",
		"target":          "cli/internal/file.go",
		"output_excerpt":  "Success. Updated the following files:",
		"output_bytes":    312,
		"output_lines":    12,
		"duration_ms":     35,
		"tok_per_sec":     18.4,
		"input_tokens":    10,
		"output_tokens":   20,
		"total_tokens":    30,
		"session_summary": "add test implementation",
	})
	require.NoError(t, err)
	events <- agentlib.ServiceEvent{
		Type: "progress",
		Time: time.Date(2026, 4, 30, 12, 0, 0, 0, time.UTC),
		Data: progressPayload,
	}
	events <- agentlib.ServiceEvent{
		Type: "final",
		Time: time.Date(2026, 4, 30, 12, 0, 1, 0, time.UTC),
		Data: json.RawMessage(`{"status":"success","exit_code":0,"final_text":"done"}`),
	}
	close(events)

	_, _, _, progress := drainServiceEvents(events)
	require.Len(t, progress, 1)
	assert.Equal(t, "ddx-1234", progress[0].TaskID)
	assert.Equal(t, 7, progress[0].TurnIndex)
	assert.Equal(t, "add test implementation", progress[0].Action)
	assert.Equal(t, "cli/internal/file.go", progress[0].Target)
	assert.Equal(t, 312, progress[0].OutputBytes)
	assert.Equal(t, 12, progress[0].OutputLines)
	require.NotNil(t, progress[0].TokPerSec)
	assert.InDelta(t, 18.4, *progress[0].TokPerSec, 0.0001)
	assert.Contains(t, FormatServiceProgressEntries(progress), "ok ddx-1234 7 add test implementation to cli/internal/file.go")
	assert.Contains(t, FormatServiceProgressEntries(progress), "< out=312B 12 lines")
	assert.Contains(t, FormatServiceProgressEntries(progress), "18.4 tok/s")
}

